export const installRaw = "pnpm add delta-agents";
export const actionRaw = "import { Ok } from \"delta-agents\";\nimport { z } from \"zod\";\n\nconst issueRefund = delta.action({\n  name: \"issue-refund\",\n  description: \"Issue a refund for an order\",\n  risk: 4,\n  requiresApproval: true,\n  schema: z.object({\n    orderId: z.string(),\n    amount: z.number().positive(),\n  }),\n  fn: async ({ orderId, amount }) => {\n    const receipt = await refundOrder(orderId, amount);\n    return Ok(receipt);\n  },\n});";
export const serviceRaw = "const supportAgent = delta.agent({\n  name: \"support-agent\",\n  description: \"Handles order support requests\",\n  role: \"Order Support Specialist\",\n  rolePrompt: \"Look up the order, then decide whether a refund is warranted.\",\n  actions: [lookupOrder, issueRefund],\n});\n\ndelta.deploy(supportAgent);";
export const serverRaw = "const result = await delta.send({\n  goal: \"Look up order ORD-1042 and refund the customer\",\n  agentName: \"support-agent\",\n  budget: { tokens: 5000, durationMs: 30_000 },\n});\n\n// result.value.status -> \"blocked\" (refund needs a human sign-off)";
export const invokeRaw = "const inspection = await delta.inspect(result.value.taskId);\nconst pending = inspection.value.pendingApprovals[0];\n\nawait delta.approve(pending.id);\nconst resumed = await delta.resume(result.value.taskId);\n\n// resumed.value.status -> \"completed\"";
